prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?messageCount) WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?def tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .

  {
    ?mf a bboExt:MessageFlow ;
        bboExt:sourceRef ?taskId ;
        bboExt:messageRef ?msg .
    FILTER(?taskId != "")
    FILTER(STRENDS(STR(?task), ?taskId))
  }
  UNION
  {
    ?mf a bboExt:MessageFlow ;
        bboExt:targetRef ?taskId ;
        bboExt:messageRef ?msg .
    FILTER(?taskId != "")
    FILTER(STRENDS(STR(?task), ?taskId))
  }

  OPTIONAL { ?task bbo:name ?taskName . }
}
GROUP BY ?task ?taskName
HAVING(COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?mf) AS ?messageFlowCount)
       (COUNT(DISTINCT ?msg) AS ?messageCount)
       (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?model tai:belongsTo ?org .

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  OPTIONAL { ?mf bboExt:messageRef ?msg . }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
    { ?mf bboExt:sourceRef ?taskId . FILTER(STRENDS(STR(?task), ?taskId)) }
    UNION
    { ?mf bboExt:targetRef ?taskId . FILTER(STRENDS(STR(?task), ?taskId)) }
  }
}
GROUP BY ?model

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?norm ?orig ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?norm . }
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(
    (?norm = "262d9e9b8c224d918fe800cd2a454ddf") ||
    (?orig = "262d9e9b8c224d918fe800cd2a454ddf") ||
    (CONTAINS(LCASE(STR(?norm)), LCASE("262d9e9b8c224d918fe800cd2a454ddf"))) ||
    (CONTAINS(LCASE(STR(?orig)), LCASE("262d9e9b8c224d918fe800cd2a454ddf")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_ece51571_13ba_41d8_8688_057c876cc093" .

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  OPTIONAL { ?mf bboExt:messageRef ?msg . }

  {
    ?mf bboExt:sourceRef ?taskId .
    FILTER(?taskId != "")
    FILTER(STRENDS(STR(?task), ?taskId))
  }
  UNION
  {
    ?mf bboExt:targetRef ?taskId .
    FILTER(?taskId != "")
    FILTER(STRENDS(STR(?task), ?taskId))
  }

  OPTIONAL { ?task bbo:name ?taskName . }
  BIND(COALESCE(?taskName, STR(?task)) AS ?taskName2)
  FILTER(BOUND(?msg) && STR(?msg) != "")
  BIND(?taskName2 AS ?taskName)
}
GROUP BY ?task ?taskName
HAVING(COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

